 11	import { NetworkPolicyEgressIngress } from './utils/types';
 12	
 13	type NetworkPolicyPeerIPBlockProps = {
 14	  direction: NetworkPolicyEgressIngress;
 15	  ipBlock: NetworkPolicyIPBlock;
 16	  onChange: (ipBlock: NetworkPolicyIPBlock) => void;
 17	};
 18	
 19	const NetworkPolicyPeerIPBlock: FC<NetworkPolicyPeerIPBlockProps> = ({
 20	  direction,
 21	  ipBlock,
 22	  onChange,
 23	}) => {
 24	  const { t } = useNetworkingTranslation();
 25	  const [networkFeatures, networkFeaturesLoaded] = useClusterNetworkFeatures();
 26	
 27	  const handleCIDRChange = (event: ChangeEvent<HTMLInputElement>) => {
 28	    ipBlock.cidr = event.currentTarget.value;
 29	    onChange(ipBlock);
 30	  };
 31	
 32	  const handleExceptionsChange = (idx: number, value: string) => {
 33	    ipBlock.except[idx].value = value;
 34	    onChange(ipBlock);
 35	  };
 36	
 37	  return (
 38	    <>
 39	      <div>
 40	        <label className="co-required" htmlFor="cidr">
 41	          {t('CIDR')}
 42	        </label>
 43	        <input
 44	          aria-describedby="ipblock-help"
 45	          className="pf-v6-c-form-control"
 46	          data-test="ipblock-cidr-input"
 47	          id="cidr"
 48	          name="cidr"
 49	          onChange={handleCIDRChange}
 50	          placeholder="10.2.1.0/16"
 51	          required
 52	          type="text"
 53	          value={ipBlock.cidr}
 54	        />
 55	        <div className="help-block">
 56	          <Text component="p">
 57	            {direction === 'ingress'
 58	              ? t('If this field is empty, traffic will be allowed from all external sources.')
 59	              : t('If this field is empty, traffic will be allowed to all external sources.')}
 60	          </Text>
 61	        </div>
 62	      </div>
 63	      {networkFeaturesLoaded && networkFeatures?.PolicyPeerIPBlockExceptions !== false && (
 64	        <div className="form-group">
 65	          <label>{t('Exceptions')}</label>
 66	          {ipBlock?.except?.map((exc, idx) => (
 67	            <div className="pf-v6-c-input-group" key={exc.key}>
 68	              <input
 69	                aria-describedby="ports-help"
 70	                className="pf-v6-c-form-control"
 71	                data-test="ipblock-exception-input"
 72	                id={`exception-${idx}`}
 73	                name={`exception-${idx}`}
 74	                onChange={(event) => handleExceptionsChange(idx, event.currentTarget.value)}
 75	                placeholder="10.2.1.0/12"
 76	                type="text"
 77	                value={exc.value}
 78	              />
 79	              <Button
 80	                aria-label={t('Remove exception')}
 81	                className="co-create-networkpolicy__remove-exception"
 82	                data-test="ipblock-remove-exception"
 83	                onClick={() => {
 84	                  ipBlock.except = [
 85	                    ...ipBlock.except.slice(0, idx),
 86	                    ...ipBlock.except.slice(idx + 1),
 87	                  ];
 88	                  onChange(ipBlock);
 89	                }}
 90	                type="button"
 91	                variant="plain"
 92	              >
 93	                <MinusCircleIcon />
 94	              </Button>
 95	            </div>
 96	          ))}
 97	          <div className="co-toolbar__group co-toolbar__group--left">
 98	            <Button
 99	              className="pf-m-link--align-left"
100	              data-test="ipblock-add-exception"
101	              onClick={() => {
102	                ipBlock.except.push({
103	                  key: uuidv4(),
104	                  value: '',
105	                });
106	                onChange(ipBlock);
107	              }}
108	              type="button"
109	              variant={ButtonVariant.link}
110	            >
111	              <PlusCircleIcon className="co-icon-space-r" />
112	              {t('Add exception')}
113	            </Button>
114	          </div>
115	        </div>
116	      )}
117	    </>
118	  );
119	};
120	
121	export default NetworkPolicyPeerIPBlock;

